def _extract_kwargs(signature: str) -> list[str]:
    kwargs: list[str] = []
    for chunk in signature.split(","):
        chunk = chunk.strip()
        if not chunk or chunk.startswith("*"):
            continue
        name = chunk.split(":", 1)[0].split("=", 1)[0].strip()
        if name:
            kwargs.append(name)
    return kwargs

